import React, { useState, useEffect, createContext, useContext, useCallback } from 'react';
import { Routes, Route, Link, useNavigate, Navigate } from 'react-router-dom';
import axios from 'axios';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './components/Register';
import HospitalDetail from './pages/HospitalDetail';

/* ── Axios defaults ───────────────────────────────────────────── */
axios.defaults.baseURL = 'http://localhost:5000';
axios.defaults.withCredentials = true;

/* ── Auth Context ─────────────────────────────────────────────── */
const AuthContext = createContext(null);
export const useAuth = () => useContext(AuthContext);

function AuthProvider({ children }) {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchUser = useCallback(async () => {
    try {
      const res = await axios.get('/api/me');
      setUser(res.data);
    } catch {
      setUser(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchUser(); }, [fetchUser]);

  const login = async (email, password) => {
    const res = await axios.post('/api/login', { email, password });
    setUser(res.data.user);
    return res.data;
  };

  const register = async (data) => {
    const res = await axios.post('/api/register', data);
    return res.data;
  };

  const logout = async () => {
    await axios.post('/api/logout');
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, register, logout, fetchUser }}>
      {children}
    </AuthContext.Provider>
  );
}

/* ── Protected Route ──────────────────────────────────────────── */
function ProtectedRoute({ children }) {
  const { user, loading } = useAuth();
  if (loading) return <div style={{textAlign:'center',padding:'4rem'}}>Loading...</div>;
  if (!user) return <Navigate to="/login" />;
  return children;
}

/* ── Navbar ───────────────────────────────────────────────────── */
function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const handleLogout = async () => {
    await logout();
    navigate('/');
  };

  return (
    <nav style={styles.nav}>
      <Link to="/" style={styles.brand}>🏥 Arogya</Link>
      <div style={styles.navLinks}>
        <Link to="/" style={styles.navLink}>Home</Link>
        {user ? (
          <>
            <Link to="/appointments" style={styles.navLink}>My Appointments</Link>
            <Link to="/notifications" style={styles.navLink}>Notifications</Link>
            <button onClick={handleLogout} style={styles.navBtn}>Logout</button>
          </>
        ) : (
          <>
            <Link to="/login" style={styles.navLink}>Login</Link>
            <Link to="/register" style={styles.navLinkHighlight}>Sign Up</Link>
          </>
        )}
      </div>
    </nav>
  );
}

/* ── Appointments Page ────────────────────────────────────────── */
function AppointmentsPage() {
  const [appointments, setAppointments] = useState([]);
  const [message, setMessage] = useState('');
  const [reschedule, setReschedule] = useState(null);
  const [newDate, setNewDate] = useState('');
  const [newTime, setNewTime] = useState('');

  const fetchAppts = useCallback(async () => {
    try {
      const r = await axios.get('/api/appointments');
      setAppointments(r.data);
    } catch {}
  }, []);

  useEffect(() => { fetchAppts(); }, [fetchAppts]);

  const cancelAppt = async (id) => {
    if (!window.confirm('Are you sure you want to cancel this appointment?')) return;
    try {
      await axios.put(`/api/appointments/${id}/cancel`);
      setMessage('Appointment cancelled');
      fetchAppts();
    } catch (e) { setMessage(e.response?.data?.error || 'Cancel failed'); }
  };

  const doReschedule = async (id) => {
    try {
      await axios.put(`/api/appointments/${id}/reschedule`, { date: newDate, time_slot: newTime });
      setMessage('Appointment rescheduled');
      setReschedule(null);
      fetchAppts();
    } catch (e) { setMessage(e.response?.data?.error || 'Reschedule failed'); }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.pageTitle}>My Appointments</h1>
      {message && <div style={styles.alert}>{message}</div>}

      {appointments.length === 0 ? (
        <div style={styles.emptyPanel}>
          <h3>No Appointments</h3>
          <p>Go to the dashboard to book your first appointment.</p>
        </div>
      ) : (
        <div style={styles.apptList}>
          {appointments.map(a => (
            <div key={a.id} style={styles.apptCard}>
              <div style={styles.apptHeader}>
                <h3 style={{margin:0}}>Dr. {a.doctor_name}</h3>
                <span style={{...styles.badge, ...(a.status === 'confirmed' ? styles.badgeConfirmed : a.status === 'cancelled' ? styles.badgeCancelled : styles.badgeCompleted)}}>
                  {a.status}
                </span>
              </div>
              <p style={{color:'#6c757d', margin:'0.25rem 0'}}>{a.hospital_name ? `🏥 ${a.hospital_name} • ` : ''}{a.specialization} • {a.department}</p>
              <p style={{margin:'0.25rem 0'}}><strong>📅 {a.date}</strong> at <strong>{a.time_slot}</strong></p>
              {a.notes && <p style={{color:'#6c757d', fontSize:'0.85rem'}}>Notes: {a.notes}</p>}

              {a.status === 'confirmed' && (
                <div style={{display:'flex', gap:'0.5rem', marginTop:'0.75rem'}}>
                  <button onClick={() => cancelAppt(a.id)} style={styles.btnDanger}>Cancel</button>
                  <button onClick={() => { setReschedule(a.id); setNewDate(a.date); setNewTime(a.time_slot); }}
                    style={styles.btnOutline}>Reschedule</button>
                </div>
              )}

              {reschedule === a.id && (
                <div style={{marginTop:'1rem', padding:'1rem', background:'#f8f9fa', borderRadius:'8px'}}>
                  <label style={styles.label}>New Date</label>
                  <input type="date" value={newDate} onChange={e => setNewDate(e.target.value)} style={styles.input} min={new Date().toISOString().split('T')[0]} />
                  <label style={{...styles.label, marginTop:'0.5rem'}}>New Time Slot</label>
                  <input type="time" value={newTime} onChange={e => setNewTime(e.target.value)} style={styles.input} />
                  <div style={{display:'flex', gap:'0.5rem', marginTop:'0.75rem'}}>
                    <button onClick={() => doReschedule(a.id)} style={styles.btnPrimary}>Confirm</button>
                    <button onClick={() => setReschedule(null)} style={styles.btnOutline}>Cancel</button>
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ── Notifications Page ───────────────────────────────────────── */
function NotificationsPage() {
  const [notifs, setNotifs] = useState([]);

  useEffect(() => {
    axios.get('/api/notifications').then(r => setNotifs(r.data)).catch(() => {});
    axios.put('/api/notifications/read').catch(() => {});
  }, []);

  const typeIcons = { booking: '📅', cancellation: '❌', reschedule: '🔄', system: 'ℹ️', info: 'ℹ️' };

  return (
    <div style={styles.container}>
      <h1 style={styles.pageTitle}>Notifications</h1>
      {notifs.length === 0 ? (
        <div style={styles.emptyPanel}><h3>No notifications</h3></div>
      ) : (
        <div style={styles.apptList}>
          {notifs.map(n => (
            <div key={n.id} style={{...styles.apptCard, opacity: n.is_read ? 0.7 : 1}}>
              <p style={{margin:0, fontSize:'1.1rem'}}>
                {typeIcons[n.type] || 'ℹ️'} {n.message}
              </p>
              <p style={{margin:'0.25rem 0 0', color:'#6c757d', fontSize:'0.8rem'}}>
                {new Date(n.created_at).toLocaleString()}
              </p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

/* ── App Root ─────────────────────────────────────────────────── */
export default function App() {
  return (
    <AuthProvider>
      <div style={{minHeight:'100vh', background:'#f0f2f5', fontFamily:"'Inter', system-ui, sans-serif"}}>
        <Navbar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/hospital/:id" element={<HospitalDetail />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/appointments" element={<ProtectedRoute><AppointmentsPage /></ProtectedRoute>} />
          <Route path="/notifications" element={<ProtectedRoute><NotificationsPage /></ProtectedRoute>} />
        </Routes>
      </div>
    </AuthProvider>
  );
}

/* ── Inline Styles ────────────────────────────────────────────── */
const styles = {
  nav: { background:'#fff', padding:'1rem 2rem', display:'flex', alignItems:'center', justifyContent:'space-between', boxShadow:'0 2px 10px rgba(0,0,0,.05)', position:'sticky', top:0, zIndex:100 },
  brand: { color:'#2D68FE', fontSize:'1.6rem', fontWeight:800, textDecoration:'none', letterSpacing:'-0.5px' },
  navLinks: { display:'flex', alignItems:'center', gap:'1rem' },
  navLink: { color:'#495057', padding:'0.5rem 1rem', borderRadius:'8px', textDecoration:'none', fontWeight:600, fontSize:'0.95rem', transition:'all .2s' },
  navLinkHighlight: { color:'#fff', padding:'0.6rem 1.5rem', borderRadius:'25px', textDecoration:'none', fontWeight:600, fontSize:'0.95rem', background:'#2D68FE', boxShadow:'0 4px 10px rgba(45, 104, 254, 0.3)' },
  navBtn: { color:'#dc3545', padding:'0.5rem 1rem', borderRadius:'8px', fontWeight:600, fontSize:'0.95rem', background:'transparent', border:'none', cursor:'pointer', fontFamily:'inherit' },

  container: { maxWidth:'1200px', margin:'0 auto', padding:'2rem 1.5rem' },
  pageTitle: { fontSize:'1.75rem', fontWeight:700, marginBottom:'0.25rem' },
  subtitle: { color:'#6c757d', marginBottom:'1.5rem' },
  sectionTitle: { fontSize:'1.15rem', fontWeight:700, marginBottom:'1rem' },

  searchBox: { marginBottom:'1.5rem' },
  searchInput: { width:'100%', padding:'0.75rem 1rem', border:'2px solid #dee2e6', borderRadius:'10px', fontSize:'1rem', fontFamily:'inherit', outline:'none', transition:'border .25s' },

  dashGrid: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:'2rem', alignItems:'start' },
  doctorList: { display:'flex', flexDirection:'column', gap:'0.75rem', maxHeight:'70vh', overflowY:'auto' },
  docCard: { display:'flex', gap:'1rem', padding:'1rem', background:'#fff', borderRadius:'12px', boxShadow:'0 2px 8px rgba(0,0,0,.06)', cursor:'pointer', transition:'all .25s', alignItems:'center' },
  docAvatar: { width:'48px', height:'48px', borderRadius:'50%', background:'linear-gradient(135deg,#667eea,#764ba2)', color:'#fff', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, fontSize:'1.25rem', flexShrink:0 },

  bookingPanel: { background:'#fff', borderRadius:'12px', boxShadow:'0 2px 12px rgba(0,0,0,.08)', padding:'1.5rem' },
  emptyPanel: { background:'#fff', borderRadius:'12px', boxShadow:'0 2px 12px rgba(0,0,0,.08)', padding:'3rem', textAlign:'center', color:'#6c757d' },

  label: { display:'block', fontWeight:600, fontSize:'0.9rem', color:'#495057', marginBottom:'0.4rem' },
  input: { width:'100%', padding:'0.65rem 0.9rem', border:'2px solid #dee2e6', borderRadius:'8px', fontSize:'0.95rem', fontFamily:'inherit', outline:'none', boxSizing:'border-box' },

  slotGrid: { display:'grid', gridTemplateColumns:'repeat(auto-fill, minmax(80px, 1fr))', gap:'0.5rem', marginBottom:'0.5rem' },
  slotBtn: { padding:'0.5rem', border:'none', borderRadius:'8px', fontSize:'0.85rem', fontWeight:600, cursor:'pointer', fontFamily:'inherit', transition:'all .25s' },
  slotAvailable: { background:'#d1e7dd', color:'#0f5132' },
  slotBooked: { background:'#f1f3f5', color:'#adb5bd', cursor:'not-allowed' },

  alert: { padding:'0.85rem 1.25rem', borderRadius:'8px', marginBottom:'1.25rem', fontWeight:500, fontSize:'0.9rem', background:'#cfe2ff', color:'#084298' },

  apptList: { display:'flex', flexDirection:'column', gap:'1rem' },
  apptCard: { background:'#fff', borderRadius:'12px', boxShadow:'0 2px 8px rgba(0,0,0,.06)', padding:'1.25rem' },
  apptHeader: { display:'flex', justifyContent:'space-between', alignItems:'center' },

  badge: { padding:'0.3rem 0.75rem', borderRadius:'50px', fontSize:'0.75rem', fontWeight:600, textTransform:'capitalize' },
  badgeConfirmed: { background:'#d1e7dd', color:'#0f5132' },
  badgeCancelled: { background:'#f8d7da', color:'#842029' },
  badgeCompleted: { background:'#e2d9f3', color:'#432874' },

  btnPrimary: { padding:'0.5rem 1rem', background:'#0d6efd', color:'#fff', border:'none', borderRadius:'8px', fontWeight:600, cursor:'pointer', fontFamily:'inherit', fontSize:'0.85rem' },
  btnDanger: { padding:'0.5rem 1rem', background:'#dc3545', color:'#fff', border:'none', borderRadius:'8px', fontWeight:600, cursor:'pointer', fontFamily:'inherit', fontSize:'0.85rem' },
  btnOutline: { padding:'0.5rem 1rem', background:'transparent', color:'#0d6efd', border:'2px solid #0d6efd', borderRadius:'8px', fontWeight:600, cursor:'pointer', fontFamily:'inherit', fontSize:'0.85rem' },
};
